import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

const mockExecSync = vi.fn();
vi.mock('node:child_process', () => ({
  execSync: (...args: unknown[]) => mockExecSync(...args),
}));

const mockGetProjectDir = vi.fn(() => '/proj');
vi.mock('../../lib/paths.js', () => ({
  getProjectDir: () => mockGetProjectDir(),
}));

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { debtSurfacer } from '../../instructions-loaded/debt-surfacer.js';
import { DEBT_TOKEN } from '../../lib/debt-markers.js';

const T = DEBT_TOKEN;

describe('debtSurfacer', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    delete process.env.ORK_DISABLE_DEBT_SURFACER;
    mockGetProjectDir.mockReturnValue('/proj');
  });

  it('returns null when grep finds nothing', () => {
    mockExecSync.mockReturnValue('');
    expect(debtSurfacer([], new Map())).toBeNull();
  });

  it('returns null when grep throws', () => {
    mockExecSync.mockImplementation(() => { throw new Error('grep failed'); });
    expect(debtSurfacer([], new Map())).toBeNull();
  });

  it('surfaces a compact ledger summary with relative paths', () => {
    mockExecSync.mockReturnValue(
      [
        `/proj/src/auth.ts:14:// ${T}: session cookies, upgrade to JWT, when a 2nd service is added`,
        `/proj/src/db.ts:8:# ${T}: SQLite, upgrade to Postgres, when writers > 1`,
      ].join('\n'),
    );
    const out = debtSurfacer([], new Map());
    expect(out).not.toBeNull();
    expect(out).toContain('[Deferred Debt]');
    expect(out).toContain('2 deliberate shortcut(s) tracked across 2 file(s)');
    expect(out).toContain('src/auth.ts:14');
    expect(out).toContain('session cookies -> JWT');
    expect(out).toContain('src/db.ts:8');
  });

  it('caps the listed markers and notes the remainder', () => {
    const lines = Array.from({ length: 8 }, (_, i) =>
      `/proj/src/f${i}.ts:${i + 1}:// ${T}: shortcut ${i}, upgrade to fix ${i}, when cond ${i}`,
    );
    mockExecSync.mockReturnValue(lines.join('\n'));
    const out = debtSurfacer([], new Map()) ?? '';
    expect(out).toContain('8 deliberate shortcut(s)');
    expect(out).toContain('...and 3 more');
  });

  it('ignores grep lines that are not valid markers', () => {
    mockExecSync.mockReturnValue('/proj/src/x.ts:3:const ork = 1; // unrelated');
    expect(debtSurfacer([], new Map())).toBeNull();
  });

  it('respects the opt-out env var', () => {
    process.env.ORK_DISABLE_DEBT_SURFACER = '1';
    mockExecSync.mockReturnValue(`/proj/src/a.ts:1:// ${T}: x, upgrade to y, when z`);
    expect(debtSurfacer([], new Map())).toBeNull();
  });
});
